import React, { useId } from 'react';
import { getInputIds, getInputAriaProps } from '../lib/core';
import type { InputBaseProps } from '../lib/core';
import styles from './input.module.scss';

export interface InputProps extends React.InputHTMLAttributes<HTMLInputElement>, InputBaseProps {}

const Input = React.forwardRef<HTMLInputElement, InputProps>(({ className = '', label, error, helperText, required, id: providedId, type = 'text', ...props }, ref) => {
	const generatedId = useId();
	const id = providedId || generatedId;
	const ids = getInputIds(id);
	const ariaProps = getInputAriaProps(ids, error, helperText);

	return (
		<div className={styles.inputWrapper}>
			{label && (
				<label htmlFor={id} className={`${styles.label} ${required ? styles.required : ''}`}>
					{label}
				</label>
			)}
			<input ref={ref} id={id} type={type} className={`${styles.input} ${error ? styles.error : ''} ${className}`} {...ariaProps} {...props} />
			{error && (
				<span id={ids.error} className={styles.errorText}>
					{error}
				</span>
			)}
			{!error && helperText && (
				<span id={ids.helper} className={styles.helperText}>
					{helperText}
				</span>
			)}
		</div>
	);
});

Input.displayName = 'Input';

export { Input };
export default Input;

@use 'sass:color';
@use '../../../styles/variables/colors' as *;

.inputWrapper {
	display: flex;
	flex-direction: column;
	gap: $spacing-1;
	width: 100%;
}

.input {
	display: flex;
	height: 2.25rem;
	width: 100%;
	border-radius: $radius;
	border: 1px solid $border;
	background-color: $background;
	padding: 0 $spacing-3;
	font-size: $text-sm;
	color: $foreground;
	transition: all $transition-fast;
	outline: none;

	&::placeholder {
		color: color.mix(white, $foreground, 60%);
	}

	&:focus {
		outline: none;
		border-color: $ring;
		box-shadow: 0 0 0 1px $ring;
	}

	&:disabled,
	&.disabled {
		pointer-events: none;
		opacity: 0.5;
		cursor: not-allowed;
		background-color: color.mix(white, $background, 50%);
	}

	&.error {
		border-color: $destructive;

		&:focus {
			border-color: $destructive;
			box-shadow: 0 0 0 1px $destructive;
		}
	}
}

.label {
	display: block;
	font-size: $text-sm;
	font-weight: $font-medium;
	color: $foreground;
	line-height: $leading-normal;

	&.required::after {
		content: ' *';
		color: $destructive;
	}
}

.helperText {
	font-size: $text-xs;
	color: color.mix(white, $foreground, 60%);
	line-height: $leading-normal;
}

.errorText {
	font-size: $text-xs;
	color: $destructive;
	line-height: $leading-normal;
}
